const OWNER='your-github-org', REPO='your-repo';
const j=$input.first().json||{};
const wf=(j.workflow&&j.workflow.name)||'Unknown workflow';
const exec=j.execution||{};
const node=exec.lastNodeExecuted||'unknown node';
const msg=(exec.error&&exec.error.message)||j.message||'No error message';
const low=msg.toLowerCase();
let category='unknown',owner='needs-triage';
if(/forbidden|unauthor|credential|401|403/.test(low)){category='auth';owner='needs-human';}
else if(/rate.?limit|429/.test(low)){category='rate-limit';owner='agent';}
else if(/timeout|econn|socket|503|502/.test(low)){category='transient';owner='auto-retry';}
else if(/not found|404/.test(low)){category='not-found';owner='agent';}
else if(/invalid|parse|schema/.test(low)){category='data/config';owner='agent';}
const issueTitle='Pipeline failure: '+wf;
const body='**Workflow:** '+wf+'\n**Node:** '+node+'\n**Category:** '+category+' | **Owner:** '+owner+'\n**Error:** '+msg;
const discord='**'+wf+'** failed at *'+node+'* — '+category+' ('+owner+')\n'+msg;
return [{ json: { owner:OWNER, repo:REPO, wf, node, msg, category, remediationOwner:owner, issueTitle, body, discord } }];

const issues=$json.body||$json||[];
const list=Array.isArray(issues)?issues:(issues.data||[]);
const ctx=$('Format & Classify').first().json;
const match=list.find(i=>i&&i.title===ctx.issueTitle);
return [{ json: Object.assign({}, ctx, { existingNumber: match?match.number:null, hasExisting: !!match }) }];
